/* Quill Design System Theme
   Install: npx shadcn add https://quill-ds.vercel.app/r/quill.json
   Fonts: Fraunces (display/heading) + Inter (body) from Google Fonts
*/

/* ─── Font imports ──────────────────────────────────────────────────────────── */
@import url('https://fonts.googleapis.com/css2?family=Fraunces:ital,opsz,wght@0,9..144,300..900;1,9..144,300..900&family=Inter:wght@400;500;600&display=swap');

/* @quill-tokens:start */
:root {
  --paper: #F5EDDD;
  --paper-warm: #EFE4CE;
  --paper-deep: #E8DCC0;
  --ink: #2A2622;
  --ink-soft: #5C524A;
  --ink-muted: #675F58;
  --terracotta: #C4684B;
  --terracotta-deep: #8A4530;
  --moss: #7A8C5C;
  --moss-deep: #5E6E43;
  --indigo: #5B6B8A;
  --indigo-deep: #44516D;
  --gold: #B89968;
  --gold-deep: #9A7D4E;
  --line-faint: rgba(42, 38, 34, 0.08);
  --line-soft: rgba(42, 38, 34, 0.12);
  --line: rgba(42, 38, 34, 0.15);
  --line-strong: rgba(42, 38, 34, 0.20);
  --line-control: #8A7F6E;
  --shadow-xs: 0 1px 2px -1px rgba(42, 38, 34, 0.12), 0 0 0 1px rgba(42, 38, 34, 0.05);
  --shadow-sm: 0 2px 4px -1px rgba(42, 38, 34, 0.14), 0 1px 2px -1px rgba(42, 38, 34, 0.08);
  --shadow: 0 4px 8px -2px rgba(42, 38, 34, 0.16), 0 2px 4px -2px rgba(42, 38, 34, 0.10);
  --shadow-lg: 0 12px 20px -4px rgba(42, 38, 34, 0.18), 0 4px 8px -4px rgba(42, 38, 34, 0.10);
  --shadow-pop: 0 20px 32px -6px rgba(42, 38, 34, 0.22), 0 8px 12px -6px rgba(42, 38, 34, 0.12);
  --ease-out: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-soft: cubic-bezier(0.22, 1, 0.36, 1);
  --dur-fast: 0.2s;
  --dur: 0.3s;
  --dur-slow: 0.5s;
  --lift: translateY(-4px);
  --lift-sm: translateY(-2px);
  --fraunces-display: "opsz" 144, "SOFT" 50, "WONK" 0;
  --fraunces-accent: "opsz" 144, "SOFT" 100, "WONK" 1;
  --fraunces-text: "opsz" 24, "SOFT" 50;
  --fraunces-caption: "opsz" 14, "SOFT" 100;
  --surface-page: var(--paper);
  --surface-card: var(--paper-warm);
  --surface-well: var(--paper-deep);
  --text-strong: var(--ink);
  --text-body: var(--ink-soft);
  --text-muted-color: var(--ink-muted);
  --text-on-ink: var(--paper);
  --text-accent-color: var(--terracotta-deep);
  --link: var(--indigo);
  --border-card: var(--line-soft);
  --border-field: var(--line-control);
  --border-divider: var(--line-faint);
  --success: var(--moss-deep);
  --warning: var(--gold-deep);
  --danger: var(--terracotta-deep);
  --info: var(--indigo);
  --radius: 0.5rem;
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.25rem;
  --space-6: 1.5rem;
  --space-7: 1.75rem;
  --space-8: 2rem;
  --space-9: 2.25rem;
  --space-10: 2.5rem;
  --space-12: 3rem;
  --space-16: 4rem;
  --space-20: 5rem;
  --space-24: 6rem;
  --space-0.5: 0.125rem;
  --space-1.5: 0.375rem;
  --space-2.5: 0.625rem;
  --border-width-0: 0px;
  --border-width-1: 1px;
  --border-width-2: 2px;
  --border-width-3: 3px;
  --border-width-4: 4px;
  --background: var(--paper);
  --foreground: var(--ink);
  --card: var(--paper-warm);
  --card-foreground: var(--ink);
  --popover: var(--paper-warm);
  --popover-foreground: var(--ink);
  --primary: var(--ink);
  --primary-foreground: var(--paper);
  --secondary: var(--paper-deep);
  --secondary-foreground: var(--ink);
  --muted: var(--paper-deep);
  --muted-foreground: var(--ink-muted);
  --accent: var(--paper-deep);
  --accent-foreground: var(--ink);
  --destructive: var(--terracotta-deep);
  --border: var(--line-soft);
  --input: var(--line-control);
  --ring: var(--ink);
  --chart-1: var(--terracotta);
  --chart-2: var(--moss);
  --chart-3: var(--indigo);
  --chart-4: var(--gold-deep);
  --chart-5: var(--ink-soft);
  --sidebar: var(--paper-warm);
  --sidebar-foreground: var(--ink);
  --sidebar-primary: var(--ink);
  --sidebar-primary-foreground: var(--paper);
  --sidebar-accent: var(--paper-deep);
  --sidebar-accent-foreground: var(--ink);
  --sidebar-border: var(--line-faint);
  --sidebar-ring: var(--ink);
  --dk-paper: #20180E;
  --dk-paper-warm: #2A2014;
  --dk-paper-deep: #352A1A;
  --dk-ink: #F1E7D3;
  --dk-ink-soft: #C8B9A0;
  --dk-ink-muted: #A89880;
  --dk-terracotta: #DB8568;
  --dk-terracotta-deep: #E89A80;
  --dk-moss: #A2B57E;
  --dk-moss-deep: #B6C896;
  --dk-indigo: #92A2C2;
  --dk-indigo-deep: #AAB8D4;
  --dk-gold: #D6BA86;
  --dk-gold-deep: #E2CA9E;
  --dk-line-faint: rgba(241, 231, 211, 0.07);
  --dk-line-soft: rgba(241, 231, 211, 0.11);
  --dk-line: rgba(241, 231, 211, 0.15);
  --dk-line-strong: rgba(241, 231, 211, 0.22);
  --dk-line-control: #746B5D;
  --dk-shadow-xs: 0 1px 2px -1px rgba(8, 5, 3, 0.40), 0 0 0 1px rgba(8, 5, 3, 0.18);
  --dk-shadow-sm: 0 2px 4px -1px rgba(8, 5, 3, 0.48), 0 1px 2px -1px rgba(8, 5, 3, 0.30);
  --dk-shadow: 0 4px 8px -2px rgba(8, 5, 3, 0.54), 0 2px 4px -2px rgba(8, 5, 3, 0.36);
  --dk-shadow-lg: 0 12px 20px -4px rgba(8, 5, 3, 0.62), 0 4px 8px -4px rgba(8, 5, 3, 0.40);
  --dk-shadow-pop: 0 20px 32px -6px rgba(8, 5, 3, 0.72), 0 8px 12px -6px rgba(8, 5, 3, 0.48);
}

[data-theme="dark"] {
  color-scheme: dark;

  --paper: var(--dk-paper);
  --paper-warm: var(--dk-paper-warm);
  --paper-deep: var(--dk-paper-deep);
  --ink: var(--dk-ink);
  --ink-soft: var(--dk-ink-soft);
  --ink-muted: var(--dk-ink-muted);
  --terracotta: var(--dk-terracotta);
  --terracotta-deep: var(--dk-terracotta-deep);
  --moss: var(--dk-moss);
  --moss-deep: var(--dk-moss-deep);
  --indigo: var(--dk-indigo);
  --indigo-deep: var(--dk-indigo-deep);
  --gold: var(--dk-gold);
  --gold-deep: var(--dk-gold-deep);
  --line-faint: var(--dk-line-faint);
  --line-soft: var(--dk-line-soft);
  --line: var(--dk-line);
  --line-strong: var(--dk-line-strong);
  --line-control: var(--dk-line-control);
  --shadow-xs: var(--dk-shadow-xs);
  --shadow-sm: var(--dk-shadow-sm);
  --shadow: var(--dk-shadow);
  --shadow-lg: var(--dk-shadow-lg);
  --shadow-pop: var(--dk-shadow-pop);
}
/* @quill-tokens:end */

/* ── Base typography ────────────────────────────────────────────────────────── */
/* In @layer base so Tailwind text-* utilities override these element defaults.
   (Unlayered, they outrank the utilities layer in Tailwind v4 — e.g. a link-
   styled CTA's text-color utility was being ignored.) */
@layer base {
  body {
    font-family: "Inter", -apple-system, BlinkMacSystemFont, sans-serif;
    line-height: 1.7;
    color: var(--ink-soft);
    background-color: var(--paper);
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: "Fraunces", Georgia, serif;
    font-weight: 400;
    letter-spacing: -0.03em;
    line-height: 1.2;
    color: var(--ink);
    font-variation-settings: var(--fraunces-text);
  }

  h1 {
    line-height: 1.05;
    font-variation-settings: var(--fraunces-display);
  }

  /* terracotta-deep via alias — meets WCAG AA (4.5:1) on paper backgrounds. */
  a { color: var(--text-accent-color); }
}

/* ── Utility classes ────────────────────────────────────────────────────────── */
.fraunces-display  { font-variation-settings: var(--fraunces-display); }
.fraunces-accent   { font-variation-settings: var(--fraunces-accent); font-style: italic; color: var(--text-accent-color); }
.fraunces-text     { font-variation-settings: var(--fraunces-text); }
.fraunces-caption  { font-variation-settings: var(--fraunces-caption); font-style: italic; color: var(--ink-muted); }
